SELECT * FROM b_purchase_order


        AND (INSTR(purchase_order_no, #{query.searchWord}) OR INSTR(project_name, #{query.searchWord}))


        AND INSTR(purchase_order_no, #{query.purchaseOrderNo})


        AND INSTR(project_name, #{query.projectName})


        AND project_id = #{query.projectId}


        AND purchase_type = #{query.purchaseType}


        AND approval_status = #{query.approvalStatus}


        AND deleted_flag = #{query.deletedFlag}


        AND create_user_id = #{query.createUserId}



    ORDER BY purchase_order_id DESC

SELECT * FROM b_purchase_order
WHERE purchase_order_no = #{purchaseOrderNo}
LIMIT 1

SELECT * FROM b_purchase_order_item
WHERE purchase_order_id = #{purchaseOrderId}
ORDER BY purchase_order_item_id ASC
